import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoriaId) => {
    setCategoriaSeleccionada(categoriaId);
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/categoria/${categoriaId}`);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  return (
    <div className="container mt-4">
      <h2 className="text-center mb-4">Categorías</h2>
      <div className="d-flex flex-wrap gap-3 justify-content-center">
        {categorias.map((cat) => (
          <button
            key={cat.id}
            className={`btn ${categoriaSeleccionada === cat.id ? "btn-primary" : "btn-outline-primary"}`}
            onClick={() => mostrarProductosPorCategoria(cat.id)}
          >
            {cat.nombre}
          </button>
        ))}
      </div>

      {categoriaSeleccionada && (
        <div className="mt-5">
          <h4 className="text-center mb-3">Productos de esta categoría</h4>
          {productos.length > 0 ? (
            <table className="table table-bordered text-center">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>Nombre</th>
                  <th>Precio</th>
                  <th>Stock</th>
                </tr>
              </thead>
              <tbody>
                {productos.map((p) => (
                  <tr key={p.id}>
                    <td>{p.id}</td>
                    <td>{p.nombre}</td>
                    <td>${p.precio}</td>
                    <td>{p.stock}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p className="text-center text-muted">No hay productos en esta categoría.</p>
          )}
        </div>
      )}
    </div>
  );
}
